--- Revenue Analysis
--- Project : Product Growth Intelligence Copilot

--- Business Question: What is the total revenue generated by the company?
--- What is the AOV (Average Order Value) for the orders?
--- What is the revenue trend over time (monthly/quarterly/yearly)?
--- Which states generate the most revenue?


select count(*) from order_items;

-- Monthly revenue trend 
select 
 ROUND(sum(price), 2) as total_revenue
 from order_items;

 --- revenue 13591643.7
 --- Average Order Value (AOV)
select 
 ROUND(sum(oi.price)*1.0/count(distinct oi.order_id), 2) as average_order_value
from order_items oi;
--- AOV 137.75

--- Revenue trend over time (monthly)
select
    strftime('%Y-%m', o.order_purchase_timestamp) as month,
    round(sum(oi.price), 2) as revenue
from orders o
join order_items oi on o.order_id = oi.order_id
group by month
order by month;

