-- Revenue by state
select 
    c.customer_state,
    round(sum(oi.price), 2) as revenue
from customers c 
join orders o
on c.customer_id = o.customer_id
join order_items oi
on o.order_id = oi.order_id
group by c.customer_state
order by revenue desc;
limit 10;

